mapper.select:
SELECT COUNT(id) as cnt
FROM member
WHERE id = #{id}

SELECT COUNT(nickname) as cnt
FROM member
WHERE nickname = #{nickname}

mapper.update:
UPDATE member
SET profile=#{profile},
    profilesaved=#{profilesaved},
    thumbs=#{thumbs},
    sizes=#{sizes}
WHERE memberno=#{memberno}

UPDATE member
SET grade=#{grade}
WHERE memberno=#{memberno}

UPDATE member
SET grade=3
WHERE memberno=#{memberno}

mapper.select:
SELECT COUNT(memberno) as cnt
FROM member
WHERE id=#{id}
  AND passwd=#{passwd}
  AND grade != 3

SELECT memberno, id, mname, tel
FROM member
WHERE mname = #{mname}
  AND tel = #{tel}

SELECT memberno, id, passwd, mname
FROM member
WHERE id = #{id}
  AND mname = #{mname}
  AND tel = #{tel}

mapper.update:
UPDATE member
SET passwd = #{passwd}
WHERE memberno = #{memberno}

mapper.select:
SELECT * FROM ( SELECT memberno, id, mname, nickname, tel, zipcode, address1, address2, mdate, grade, birth, sex, intro, manner_temp, match_cnt, latitude, longitude, location_update, profile, profilesaved, thumbs, sizes, rownum as r FROM ( SELECT memberno, id, mname, nickname, tel, zipcode, address1, address2, mdate, grade, birth, sex, intro, manner_temp, match_cnt, latitude, longitude, location_update, profile, profilesaved, thumbs, sizes FROM member
( UPPER(id) LIKE '%' || UPPER(#{word}) || '%' OR UPPER(mname) LIKE '%' || UPPER(#{word}) || '%' )
ORDER BY mdate DESC ) ) WHERE r >= #{start_num} AND r <= #{end_num}

SELECT COUNT(*) as cnt
FROM member



    grade = #{word}

SELECT * FROM ( SELECT memberno, id, mname, nickname, tel, zipcode, address1, address2, mdate, grade, birth, sex, intro, manner_temp, match_cnt, latitude, longitude, location_update, profile, profilesaved, thumbs, sizes, rownum as r FROM ( SELECT memberno, id, mname, nickname, tel, zipcode, address1, address2, mdate, grade, birth, sex, intro, manner_temp, match_cnt, latitude, longitude, location_update, profile, profilesaved, thumbs, sizes FROM member
grade = #{word}
ORDER BY mdate DESC ) ) WHERE r >= #{start_num} AND r <= #{end_num}

mapper.update:
UPDATE member
SET manner_temp = manner_temp + 0.5
WHERE memberno = #{memberno}

UPDATE member
SET manner_temp = manner_temp - 0.5
WHERE memberno = #{memberno}

UPDATE member SET manner_temp = CASE
WHEN manner_temp + #{delta} > 99 THEN 99
WHEN manner_temp + #{delta} < 0 THEN 0
ELSE manner_temp + #{delta}
END WHERE memberno = #{memberno}

UPDATE member
SET match_cnt = match_cnt + 1
WHERE memberno = #{memberno}

mapper.select:
SELECT memberno, id, mname, nickname,
       manner_temp, match_cnt,
       latitude, longitude,
       profile, thumbs
FROM member
WHERE latitude BETWEEN #{min_lat} AND #{max_lat}
  AND longitude BETWEEN #{min_lon} AND #{max_lon}
  AND memberno != #{memberno}
  AND grade = 1
